migrate(
	(app) => {
		for (const [name, urls] of MUSCLEWIKI_VIDEOS) {
			let record;
			try {
				record = app.findFirstRecordByData("exercises", "name", name);
			} catch {
				continue;
			}
			const videos = JSON.parse(record.getString("videos") || "[]");
			for (const url of urls) {
				if (!videos.includes(url)) videos.push(url);
			}
			record.set("videos", videos);
			app.save(record);
		}
	},
	(app) => {
		const records = app.findRecordsByFilter("exercises", "videos != ''", "", 0, 0);
		for (const record of records) {
			const videos = JSON.parse(record.getString("videos") || "[]");
			const kept = videos.filter((url) => !url.includes("media.musclewiki.com"));
			if (kept.length !== videos.length) {
				record.set("videos", kept);
				app.save(record);
			}
		}
	},
);
